#include<bits/stdc++.h>
using namespace std;

const int N = 1e5 + 5, M = 1e6 + 5;
int n, m, ans = -2e9;
vector<int> e[M];
int in[N], topo[N], dp[N][10], out[N], In[N], a[N];

bool toposort()
{
	int t = 0;
	queue<int> q;
	for(int i = 1; i <= n; i++)
		if(!in[i]) q.push(i);
	for(int i = 1; i <= n; i++)
		dp[i][a[i]] = 1;
	while(!q.empty())
	{
		int u = q.front();
		q.pop();
		topo[++t] = u;
		for(int v : e[u])
		{
			in[v]--;if(!in[v]) q.push(v);
			for(int i = 1; i <= a[v]; i++){
				dp[v][a[v]] = max(dp[v][a[v]], dp[u][i] + 1);
			}
			for(int i=1;i<=10;i++){
				dp[v][i] = max(dp[v][i], dp[u][i]);
			}
		}
	}
	return t == n;
}

int main()
{
	cin >> n >> m;
	for(int i = 1; i <= n; i++)
		cin >> a[i];
	for(int i = 1; i <= m; i++)
	{
		int u, v;
		cin >> u >> v;
		e[u].push_back(v);
		in[v]++;
		In[v]++;
		out[u]++;
	}
	toposort();
	for(int i = 1; i <= n; i++){
		for(int j = 1; j <= 10; j++){
		    ans = max(ans, dp[i][j]); 
		}
	}
	cout << ans;
	return 0;
}
